starter:
// var leaks out of the for block:
for (var i = 0; i < 3; i++) { /* ... */ }
console.log("var i after loop:", i); // 3 — it escaped!

// let stays inside the block:
for (let j = 0; j < 3; j++) { /* ... */ }
try {
  console.log(j); // ReferenceError
} catch(e) {
  console.log("let j is not accessible outside the loop");
}

instruction:
This is JavaScript's most infamous beginner trap. `var` loops with `setTimeout` give unexpected results:

```js
for (var i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 0);
}
// Prints: 3, 3, 3 — NOT 0, 1, 2!
```

Because `var i` is shared — by the time the callbacks run, the loop has finished and `i` is 3.

`let` fixes this by creating a new binding per iteration.

Fix the loop by changing `var` to `let`.

starter:
// BUG: prints 3, 3, 3 instead of 0, 1, 2
for (var i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 0);
}

// Function declarations are fully hoisted:
console.log(sayHi()); // works!
function sayHi() { return "Hi!"; }

// var is hoisted as undefined:
console.log(x); // undefined, not an error
var x = 5;
console.log(x); // 5

// let is in the TDZ — accessing before declaration crashes:
try {
  console.log(y); // TDZ — ReferenceError
  let y = 10;
} catch(e) {
  console.log("TDZ error:", e.message);
}

function makeCounter(start = 0) {
  let count = start;

  return function() {
    count++;
    return count;
  };
}

const counter1 = makeCounter();
const counter2 = makeCounter(10);

console.log(counter1()); // 1
console.log(counter1()); // 2
console.log(counter1()); // 3
console.log(counter2()); // 11 — separate from counter1!

instruction:
Closures are the classic way to create **private state** — variables that can only be accessed through provided methods:

```js
const counter = (function() {
  let _count = 0;  // private!
  return {
    increment() { _count++; },
    get() { return _count; }
  };
})();
```

The `_count` is completely hidden — no one can set it directly.

Run this.

starter:
function createBankAccount(initialBalance) {
  let balance = initialBalance;  // private!

  return {
    deposit(amount)  { balance += amount; },
    withdraw(amount) {
      if (amount > balance) throw new Error("Insufficient funds");
      balance -= amount;
    },
    getBalance()     { return balance; }
  };
}

const account = createBankAccount(100);
account.deposit(50);
account.withdraw(30);
console.log(account.getBalance()); // 120

try {
  console.log(account.balance); // undefined — private!
} catch(e) { console.log("private"); }
console.log(account.balance); // undefined

const messages = ["Hello", "World", "JavaScript"];

// Each callback closes over 'i' and 'msg':
messages.forEach((msg, i) => {
  // Arrow function creates a closure over 'i' and 'msg'
  setTimeout(() => {
    console.log(`${i + 1}: ${msg}`);
  }, i * 100);  // delay increases so they print in order
});

function memoize(fn) {
  const cache = new Map(); // closure — cache persists between calls!
  return function(...args) {
    const key = JSON.stringify(args);
    if (cache.has(key)) {
      console.log(`(cached)`);
      return cache.get(key);
    }
    const result = fn(...args);
    cache.set(key, result);
    return result;
  };
}

const slowSquare = memoize(n => {
  // Simulate slow computation
  return n * n;
});

console.log(slowSquare(5));  // computed
console.log(slowSquare(5));  // cached!
console.log(slowSquare(10)); // computed
console.log(slowSquare(10)); // cached!
